var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"다, 당주님! 저는 괜찮습니다!","JPN":"と、当主！　私は大丈夫です！","ENG":"M-my lady! I am fine!","TWN":"堂，堂主，我沒關係！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"내가 안 괜찮아. 치후유. 오늘은 무슨 일이 있어도 이 언니랑 같이 나가야겠어.","JPN":"私が大丈夫じゃないの、千冬。今日は何があっても私と一緒に出かけてもらうわ。","ENG":"I am the one who is not fine, Chifuyu. I will not let you stay in another day. You must come out with me.","TWN":"可是我有關係。千冬，今天你無論如何都要跟姊姊出去一趟。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주의 명령이야. 나를 호위하는 건 좋지만……","JPN":"当主の命令よ。私の護衛もいいけど……","ENG":"It is your lady's order. I understand that you are trying to protect me, but...","TWN":"這是堂主的命令，雖然保護我沒什麼問題…"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"온종일 에어컨과 얼음이 없으면 견디질 못하고 있잖아.","JPN":"熱いからって、一日中エアコンと氷に張り付いているじゃない。","ENG":"You can't stand it without air conditioning and ice all the time.","TWN":"但怎麼可以整天待在沒有冷氣和冰塊的地方。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"게다가 이렇게 실내에만 있으면 마음이 병들어 버려.","JPN":"それにこうやって屋内にばかりにいたら、心が病んでしまうわ。","ENG":"Continually staying indoors will plague your mind.","TWN":"而且這樣一直待在室內，心情會變差的。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그, 그건 당주님도 마찬가지 아니신지요.","JPN":"そ、それは当主も同じではありませんか。","ENG":"W-well, you are no different, my lady.","TWN":"那，那堂主不也一樣嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"으응?","JPN":"ううん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"저는 당주님을 곁에서 지키는 사람입니다.","JPN":"私の役目は当主をおそばでお守りすることです。","ENG":"I am supposed to protect you by your side.","TWN":"我是守在堂主身邊的人。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"하지만 당주님께서도 요즘 도통 밖에 나가질 않으시니……","JPN":"ですが、近頃は当主も全然外出されないので……","ENG":"But you hardly go out these days either...","TWN":"但堂主最近根本就不出門…"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"덩달아 저도 당주님 옆에서 에어컨을 쐬고 있을 뿐입니다.","JPN":"私もつられて当主のおそばでエアコンにあたっていただけです。","ENG":"So I simply stay by your side under the air conditioning breeze.","TWN":"我待在堂主身旁，也只是陪你吹冷氣而已。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"수련은 가옥의 마당에서 따로 하고 있으니 걱정하지 않으셔도 됩니다.","JPN":"修練は家の庭でしていますので、ご心配には及びません。","ENG":"And I have been training out at the courtyard, so you do not need to worry.","TWN":"我自己會另外在院子修練的，不用堂主擔心。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"크흠. 마당에서 검만 휘둘러서도 안 된다고 생각해.","JPN":"こほん。庭で刀を振るうだけではダメだと思うわ。","ENG":"Ahem. Well, I think you should do more than just swing your sword in the courtyard.","TWN":"咳哼，光在院子裡揮劍也不行吧。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"마침 잘되었군요. 당주님.","JPN":"ちょうど良かったです。ご当主様。","ENG":"That is perfect then, Lady Nanahara.","TWN":"那這樣正好，堂主。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"스승님……?","JPN":"師匠……？","ENG":"Master...?","TWN":"師父……？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"몸이 늘어진다고 하여 집안에만 있는 것은 심신을 병들게 합니다.","JPN":"体がだるいからといって屋内にばかりいては、心身ともに病に冒されやすくなります。","ENG":"Staying indoors simply because you feel sluggish will affect both your mind and body.","TWN":"身體懶散就待在家裡，這樣對身心都不好。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이참에 두 분 다 외출하시는 게 어떠한지요.","JPN":"この際、お二人とも外出なさってはいかがですか？","ENG":"How about you both take this chance to go out?","TWN":"這次不如二位都出門吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"맞아. 치후유. 사나에도 이렇게 말하잖아. 얼른 외출할 채비를 하렴.","JPN":"そうよ、千冬。早苗もああ言ってるじゃない。早く外に出る準備をしなさい。","ENG":"Yes, Chifuyu. Even Sanae is saying so. Get ready to head out, now.","TWN":"沒錯，千冬。連早苗都這麼說了，快去準備出門吧。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님이 가옥에만 있다 하여 게을러지는 것은 치후유 님에게도 좋지 않습니다.","JPN":"ご当主様が家にばかりいて怠惰になることは、千冬様にもよろしくありません。","ENG":"Becoming lazy because Lady Nanahara prefers to stay indoors will not do you any good, Miss Chifuyu.","TWN":"堂主待在家裡變懶對千冬也不好。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"흠흠. 그래서 나가려는 거예요.","JPN":"おほん。それで出かけようとしているのです。","ENG":"Ahem. That is why we are going to go for a stroll.","TWN":"咳咳，所以才要出門的嘛。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"간만에 두 분만의 시간을 보내시죠. 지난여름에도 그러셨던 걸로 기억합니다만.","JPN":"久々にお二人だけの時間をお過ごしください。去年の夏もそうされていたと記憶しておりますが。","ENG":"You two should spend some time alone together. I recall you doing that last summer, too.","TWN":"機會難得，你們二個就一起出去走走吧，我記得去年夏天你們不是也有一起出門嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유. 방 안에서 열을 식히는 것도 좋지만 때로는……","JPN":"千冬。部屋の中で熱を冷ますのもいいけれど、たまには……","ENG":"Chifuyu, it is good to stay in and cool yourself, but sometimes...","TWN":"千冬，雖然在房間裡降溫也很好，但有時候……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"밖에 나가서 기분 전환을 하는 것도 좋지 않을까?","JPN":"外に出て気分転換をするのもよくない？","ENG":"It might also be nice to go out and get some fresh air.","TWN":"出去走走轉換一下心情也不錯吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님이 그렇게 말씀하신다면……","JPN":"当主がそうおっしゃるのであれば……","ENG":"If you say so, my lady...","TWN":"既然堂主這麼說……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결정되었군요. 당주님. 그라운드 원으로 향하시죠.","JPN":"決まりですね、ご当主様。グラウンド・ワンへお向かいください。","ENG":"Then it is decided. You should head to Ground One, my lady.","TWN":"就這麼決定囉。堂主，就去G1吧。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"최근에 아는 분께서 유원지 티켓을 주셨습니다.","JPN":"この前、知人から遊園地のチケットを譲り受けました。","ENG":"A friend of mine recently gave me tickets to an amusement park.","TWN":"最近有位朋友送給我遊樂園的門票。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};